import numpy as np

def validate(arr):
    if arr.ndim != 1 or arr.dtype != np.float64:
        raise ValueError("expected 1d float64")
    return arr.size

print("ok", validate(np.array([1.0, 2.0], dtype=np.float64)), end="")
try:
    validate(np.array([1, 2], dtype=np.int64))
except ValueError as e:
    print(" | err", e)
